import { ApiProperty } from '@nestjs/swagger';
import {
  IsBoolean,
  IsEnum,
  IsNotEmpty,
  IsNumber,
  IsOptional,
  IsString,
  IsUUID,
  ValidateNested,
} from 'class-validator';
import {
  AddressType,
  UserNotificationsSetting,
  UserSetting,
  UserSettings,
} from '@/db';
import { NotificationsSettingDto } from '@/api/admin/settings/dtos';
import { Type } from 'class-transformer';
import { SUPPORTED_CURRENCIES, SupportedCurrency } from '@/common/currency';

export class UpdateProfileRequestDto {
  @ApiProperty()
  @IsString()
  @IsNotEmpty()
  firstName: string;

  @ApiProperty()
  @IsString()
  @IsNotEmpty()
  lastName: string;

  @ApiProperty({ required: false })
  @IsString()
  @IsOptional()
  patronymic?: string;
}

export class UpdateProfilePhotoRequestDto {
  @ApiProperty({ nullable: true })
  @IsUUID()
  @IsOptional()
  photoFileId: string | null;
}

export class UpdateAddressRequestDto {
  @ApiProperty({
    description:
      'Address identifier — provide to update an existing address, omit to create a new one',
    required: false,
  })
  @IsUUID()
  @IsOptional()
  id?: string;

  @ApiProperty({
    description: 'Country identifier',
    example: 'country-123',
  })
  @IsUUID()
  countryId: string;

  @ApiProperty({
    description: 'State',
    example: 'New York',
  })
  @IsString()
  state: string;

  @ApiProperty({
    description: 'City',
    example: 'New York',
  })
  @IsString()
  city: string;

  @ApiProperty({
    description: 'Zip code',
    example: '10001',
  })
  @IsString()
  zip: string;

  @ApiProperty({
    description: 'Address line 1',
    example: '123 Main St',
  })
  @IsString()
  addressLine1: string;

  @ApiProperty({
    description: 'Address line 2',
    example: 'Apt 1',
  })
  @IsString()
  addressLine2: string;

  @ApiProperty({
    description: 'Landmark',
    example: 'Near XYZ',
    required: false,
  })
  @IsString()
  @IsOptional()
  landmark?: string;

  @ApiProperty({
    description: 'Latitude',
    example: 40.7128,
    required: false,
  })
  @IsNumber()
  @IsOptional()
  latitude?: number;

  @ApiProperty({
    description: 'Longitude',
    example: -74.006,
    required: false,
  })
  @IsNumber()
  @IsOptional()
  longitude?: number;

  @ApiProperty({
    description: 'Mark as primary address',
    example: true,
    required: false,
  })
  @IsBoolean()
  @IsOptional()
  isPrimary?: boolean;

  @ApiProperty({
    description: 'Address type',
    enum: AddressType,
    example: AddressType.Home,
    required: false,
  })
  @IsEnum(AddressType)
  @IsOptional()
  addressType?: AddressType;
}

class UserNotificationsDto implements UserNotificationsSetting {
  @ApiProperty()
  @IsBoolean()
  general: boolean;

  @ApiProperty()
  @IsBoolean()
  buyback: boolean;

  @ApiProperty()
  @IsBoolean()
  authenticator: boolean;

  @ApiProperty()
  @IsBoolean()
  accountSecurity: boolean;
}

export class UpdateSettingsRequestDto {
  @ApiProperty()
  @IsOptional()
  @Type(() => UserNotificationsDto)
  @ValidateNested()
  [UserSetting.Notifications]: UserNotificationsDto;

  @ApiProperty({ enum: SUPPORTED_CURRENCIES, required: false })
  @IsEnum(SUPPORTED_CURRENCIES)
  @IsOptional()
  [UserSetting.Currency]?: SupportedCurrency;
}

