import { Body, Controller, Delete, Get, Param, Patch } from '@nestjs/common';
import { ApiExtraModels, ApiTags } from '@nestjs/swagger';

import { Protected } from '@/modules/auth';
import { ContextService } from '@/modules/global';
import { UserService } from '@/modules/user';
import { UserRole } from '@/db';
import {
  AddressDto,
  ProfileResponseDto,
  UpdateAddressRequestDto,
  UpdateProfilePhotoRequestDto,
  UpdateProfileRequestDto,
  UpdateSettingsRequestDto,
} from './dtos';
import {
  DeleteAddressOpenApi,
  GetAddressOpenApi,
  GetProfileOpenApi,
  GetSettingsOpenApi,
  UpdateAddressOpenApi,
  UpdateProfileOpenApi,
  UpdateProfilePhotoOpenApi,
  UpdateSettingsOpenApi,
} from './profile.openapi';

@ApiTags('App / Profile')
@ApiExtraModels(ProfileResponseDto)
@Controller()
@Protected([
  UserRole.Bidder,
  UserRole.Seller,
  UserRole.Retailer,
  UserRole.Authenticator,
  UserRole.Admin,
  UserRole.SuperAdmin,
])
export class ProfileController {
  constructor(
    private readonly userService: UserService,
    private readonly contextService: ContextService,
  ) {}

  @Get('/')
  @GetProfileOpenApi()
  async getProfile(): Promise<ProfileResponseDto> {
    const user = this.contextService.context.user;

    const userEntity = await this.userService.getOne(user.id);

    return ProfileResponseDto.mapFromEntity(userEntity);
  }

  @Get('/address')
  @GetAddressOpenApi()
  async getAddress(): Promise<AddressDto[]> {
    const user = this.contextService.context.user;

    const addresses = await this.userService.getAddress(user.id);

    return addresses.map(AddressDto.mapFromEntity);
  }

  @Patch('/')
  @UpdateProfileOpenApi()
  async updateProfile(
    @Body() body: UpdateProfileRequestDto,
  ): Promise<{ success: boolean }> {
    const user = this.contextService.context.user;

    await this.userService.updateOne(user.id, body);

    return { success: true };
  }

  @Patch('/photo')
  @UpdateProfilePhotoOpenApi()
  async updateProfilePhoto(
    @Body() body: UpdateProfilePhotoRequestDto,
  ): Promise<{ success: boolean }> {
    const user = this.contextService.context.user;

    await this.userService.updatePhoto(user.id, body.photoFileId);

    return { success: true };
  }

  @Patch('/address')
  @UpdateAddressOpenApi()
  async updateAddress(
    @Body() body: UpdateAddressRequestDto,
  ): Promise<AddressDto> {
    const user = this.contextService.context.user;

    const address = await this.userService.updateAddress(user.id, body);

    return AddressDto.mapFromEntity(address);
  }

  @Delete('/address/:id')
  @DeleteAddressOpenApi()
  async deleteAddress(@Param('id') id: string): Promise<{ success: boolean }> {
    const user = this.contextService.context.user;

    await this.userService.deleteAddress(user.id, id);

    return { success: true };
  }

  @Get('/settings')
  @GetSettingsOpenApi()
  async getSettings() {
    const user = this.contextService.context.user;
    return this.userService.getSettings(user.id);
  }

  @Patch('settings')
  @UpdateSettingsOpenApi()
  async updateSettings(@Body() body: UpdateSettingsRequestDto) {
    const user = this.contextService.context.user;

    await this.userService.updateSettings(user.id, body);

    return { success: true };
  }
}

